// src/stores/cart.store.ts
import { create } from 'zustand'
import { persist } from 'zustand/middleware'
import type { CartItem, Product } from '@/types'

interface CartStore {
  items: CartItem[]
  branch_id: string | null
  addItem: (product: Product, quantity: number, branch_id: string) => void
  removeItem: (productId: string) => void
  updateQuantity: (productId: string, quantity: number) => void
  clearCart: () => void
  total: () => number
  itemCount: () => number
}

export const useCartStore = create<CartStore>()(
  persist(
    (set, get) => ({
      items: [],
      branch_id: null,

      addItem: (product, quantity, branch_id) => {
        const existing = get().items.find(i => i.product.id === product.id)
        if (existing) {
          set({
            items: get().items.map(i =>
              i.product.id === product.id
                ? { ...i, quantity: i.quantity + quantity }
                : i
            )
          })
        } else {
          set({ items: [...get().items, { product, quantity, branch_id }], branch_id })
        }
      },

      removeItem: (productId) =>
        set(s => ({ items: s.items.filter(i => i.product.id !== productId) })),

      updateQuantity: (productId, quantity) =>
        set(s => ({
          items: quantity <= 0
            ? s.items.filter(i => i.product.id !== productId)
            : s.items.map(i => i.product.id === productId ? { ...i, quantity } : i)
        })),

      clearCart: () => set({ items: [], branch_id: null }),
      total: () => get().items.reduce((acc, i) => acc + i.product.price * i.quantity, 0),
      itemCount: () => get().items.reduce((acc, i) => acc + i.quantity, 0),
    }),
    { name: 'seraso-cart' }
  )
)